import React, { useState, useRef, useEffect } from 'react';
import { type LogEntry, LogLevel } from '../types';
import { DocumentTextIcon, TrashIcon, ArrowDownIcon, ArrowUpIcon } from './icons/Icons';

interface LogViewerProps {
  logs: LogEntry[];
  onClearLogs: () => void;
}

const getLogLevelColor = (level: LogLevel): string => {
  switch (level) {
    case LogLevel.INFO:
      return 'text-sky-400';
    case LogLevel.WARN:
      return 'text-amber-400';
    case LogLevel.ERROR:
      return 'text-red-400';
    case LogLevel.SUCCESS:
        return 'text-emerald-400';
    default:
      return 'text-slate-400';
  }
};

const LogViewer: React.FC<LogViewerProps> = ({ logs, onClearLogs }) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [showScrollBottom, setShowScrollBottom] = useState(false);
  const [showScrollTop, setShowScrollTop] = useState(false);

  const scrollToBottom = (behavior: 'smooth' | 'auto' = 'smooth') => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollTo({
        top: scrollContainerRef.current.scrollHeight,
        behavior,
      });
    }
  };

  const scrollToTop = (behavior: 'smooth' | 'auto' = 'smooth') => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollTo({
        top: 0,
        behavior,
      });
    }
  };

  useEffect(() => {
    // Auto-scroll to bottom on new logs, but only if the user hasn't scrolled up.
    if (!showScrollBottom) {
      scrollToBottom('auto');
    }
  }, [logs, showScrollBottom]);

  const handleScroll = () => {
    const container = scrollContainerRef.current;
    if (container) {
      // "Scroll to Bottom" button visibility
      const isAtBottom = container.scrollHeight - container.scrollTop - container.clientHeight < 10;
      setShowScrollBottom(!isAtBottom);

      // "Scroll to Top" button visibility
      const hasScrolledDown = container.scrollTop > container.clientHeight;
      setShowScrollTop(hasScrolledDown);
    }
  };


  return (
    <div className="bg-slate-800/50 rounded-lg p-5 border border-slate-700/50 shadow-md h-96 flex flex-col">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center">
          <DocumentTextIcon className="h-6 w-6 mr-3 text-slate-400" />
          <h3 className="text-lg font-semibold text-slate-200">Sync Logs</h3>
        </div>
        <button
          onClick={onClearLogs}
          className="inline-flex items-center px-3 py-1 border border-slate-600 text-xs font-medium rounded-md text-slate-300 bg-slate-700 hover:bg-slate-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-800 focus:ring-red-500 transition-colors"
          aria-label="Clear logs"
        >
          <TrashIcon className="h-4 w-4 mr-2" />
          Clear
        </button>
      </div>
      <div className="relative flex-grow">
        <div 
            ref={scrollContainerRef}
            onScroll={handleScroll}
            className="absolute inset-0 bg-slate-900/70 rounded-md p-3 overflow-y-auto font-mono text-xs"
        >
            {logs.map((log, index) => (
            <div key={index} className="flex">
                <span className="text-slate-500 mr-3">
                {new Date(log.timestamp).toLocaleTimeString()}
                </span>
                <span className={`font-bold mr-3 ${getLogLevelColor(log.level)}`}>
                [{log.level}]
                </span>
                <span className="flex-1 text-slate-300 whitespace-pre-wrap">
                {log.message}
                </span>
            </div>
            ))}
        </div>
        {showScrollTop && (
            <button
            onClick={() => scrollToTop('smooth')}
            className="absolute bottom-16 right-4 bg-emerald-600 hover:bg-emerald-500 text-white rounded-full p-2 shadow-lg focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 focus:ring-emerald-500 transition-opacity"
            aria-label="Scroll to top"
            >
            <ArrowUpIcon className="h-5 w-5" />
            </button>
        )}
        {showScrollBottom && (
            <button
            onClick={() => scrollToBottom('smooth')}
            className="absolute bottom-4 right-4 bg-emerald-600 hover:bg-emerald-500 text-white rounded-full p-2 shadow-lg focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 focus:ring-emerald-500 transition-opacity"
            aria-label="Scroll to bottom"
            >
            <ArrowDownIcon className="h-5 w-5" />
            </button>
        )}
      </div>
    </div>
  );
};

export default LogViewer;

